SELECT COUNT(DISTINCT S.PK_SIAPE) AS TOTAL FROM SERVIDOR S JOIN CALC_HORA_AULA_MEDIA C ON S.PK_SIAPE = C.SIAPE WHERE C.ANO = 2023 AND C.SEMESTRE = 2 AND LOWER(C.SIGLA_CAMPUS) = LOWER('ana') AND LOWER(S.CONTRATO) = LOWER('efetivos') AND (LOWER(S.AREA_INGRESSO) LIKE LOWER('%matemat%') OR LOWER(S.AREA_INGRESSO_OG) LIKE LOWER('%matemat%'))